import React, { useEffect, useState } from "react";
import API from "../api";
import Hero from "../components/Hero";
import ProductCard from "../components/ProductCard";
import Footer from "../components/Footer";
import "../styles/index.css";

export default function Home() {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    API.get("/products")
      .then(res => setProducts(res.data))
      .catch(err => console.log(err));
  }, []);

  return (
    <div>

      {/* HERO */}
      <Hero />

      {/* BRAND STRIP */}
      <div className="brands">
        <h3>VERSACE</h3>
        <h3>ZARA</h3>
        <h3>GUCCI</h3>
        <h3>PRADA</h3>
        <h3>CALVIN KLEIN</h3>
      </div>

      {/* NEW ARRIVALS */}
      <h2 className="title">NEW ARRIVALS</h2>
      <div className="grid">
        {products.slice(0, 4).map(p => (
          <ProductCard key={p._id} product={p} />
        ))}
      </div>

      {/* TOP SELLING */}
      <h2 className="title">TOP SELLING</h2>
      <div className="grid">
        {products.slice(4, 8).map(p => (
          <ProductCard key={p._id} product={p} />
        ))}
      </div>

      {/* CATEGORIES */}
      <h2 className="title">BROWSE BY STYLE</h2>
      <div className="categories">
        <div className="cat">Men</div>
        <div className="cat">Women</div>
        <div className="cat">Casual</div>
        <div className="cat">Formal</div>
      </div>

      {/* TESTIMONIAL */}
      <div className="testimonial">
        <h2>What Our Customers Say</h2>
        <p>⭐⭐⭐⭐⭐ “Amazing quality and fast delivery!”</p>
        <p>⭐⭐⭐⭐ “Loved the collection and styles.”</p>
      </div>

      {/* NEWSLETTER */}
      <div className="newsletter">
        <h2>Stay Updated</h2>
        <p>Subscribe for latest offers & updates</p>
        <input placeholder="Enter your email" />
        <button>Subscribe</button>
      </div>

      {/* FOOTER */}
      <Footer />

    </div>
  );
}
